import * as React from "react"

import { APP } from "./data"
import { TaxiRideApp } from "./TaxiRideApp"

export const metadata = {
  title: `配車 ｜ ${APP.brand}（${APP.app}）`,
  description:
    "タクシー配車アプリの乗客向け画面。乗車地・行き先の指定、車種・支払い方法の選択、マッチング済み車両の接近（到着まで○分）、料金見積もり、降車後のお支払いまでを一画面で。",
}

export default function TaxiRidePage() {
  return <TaxiRideApp />
}

// 配車アプリのモック内容（GO / S.RIDE 風の「みやこタクシー」配車）。
// 固定スナップショット（21:14 時点・接近中）。相対時刻はクライアントで再計算しない。

export const APP = {
  brand: "みやこタクシー",
  app: "MIYAKO RIDE",
} as const

export type CarClassId = "standard" | "large" | "premium"

export interface CarClass {
  id: CarClassId
  /** JPNタクシー / セダン / ワゴン / 黒塗り */
  name: string
  /** 車種の補足（定員・車種例） */
  description: string
  /** 見積もり下限（初乗り＋迎車込み） */
  estimateFrom: number
  estimateTo: number
  etaMin: number
  /** 「人気」「黒タク」などのタグ */
  tag?: string
}

export const CAR_CLASSES: CarClass[] = [
  {
    id: "standard",
    name: "普通車（JPNタクシー）",
    description: "4名まで・トヨタ JPN TAXI / クラウンコンフォート",
    estimateFrom: 1480,
    estimateTo: 1780,
    etaMin: 4,
    tag: "最短",
  },
  {
    id: "large",
    name: "大型・ワゴン",
    description: "5〜6名・トヨタ アルファード / ハイエース",
    estimateFrom: 2100,
    estimateTo: 2480,
    etaMin: 9,
  },
  {
    id: "premium",
    name: "プレミアム（黒タク）",
    description: "ハイヤー仕様・センチュリー / クラウン（黒塗り）",
    estimateFrom: 3200,
    estimateTo: 3800,
    etaMin: 12,
    tag: "上質",
  },
]

export type PaymentId = "credit" | "dpay" | "paypay" | "cash"

export interface PaymentMethod {
  id: PaymentId
  label: string
  detail: string
}

export const PAYMENTS: PaymentMethod[] = [
  { id: "credit", label: "クレジットカード", detail: "Visa •••• 4218（アプリ決済）" },
  { id: "dpay", label: "d払い", detail: "ドコモ回線と連携済み" },
  { id: "paypay", label: "PayPay", detail: "残高 ¥3,540" },
  { id: "cash", label: "現金", detail: "車内でお支払い" },
]

// 乗車地・行き先
export const TRIP = {
  pickup: {
    label: "渋谷スクランブルスクエア 前",
    address: "東京都渋谷区渋谷2-24-12",
  },
  dropoff: {
    label: "六本木ヒルズ ノースタワー",
    address: "東京都港区六本木6-2-31",
  },
  distanceKm: 4.6,
  estDurationMin: 16,
} as const

// マッチング済みの車両・乗務員
export const MATCH = {
  driverName: "佐藤 健一",
  driverRating: 4.92,
  driverReviews: 1284,
  trips: 8420,
  carClassName: "JPNタクシー（セダン）",
  carColor: "ジャパンタクシー ディープブルー",
  plate: "品川 500 あ 24-18",
  etaMin: 4,
  // 接近中の進捗（0–100）
  approachPct: 62,
} as const

// 確定運賃の内訳（降車後の支払い）
export const FARE = {
  base: 500, // 初乗り（1.096kmまで）
  distance: 880, // 加算（距離・時間併用）
  pickupFee: 420, // 迎車料金
  lateNight: 220, // 深夜割増（22時以降）
  highway: 0, // 高速代
  total: 2020,
} as const

// 配車履歴
export interface RideHistory {
  id: string
  date: string
  from: string
  to: string
  fare: number
  carClass: string
}

export const HISTORY: RideHistory[] = [
  { id: "r-0628", date: "6/27 23:40", from: "新宿駅 南口", to: "中目黒駅", fare: 2680, carClass: "普通車" },
  { id: "r-0625", date: "6/25 19:02", from: "東京駅 八重洲", to: "品川プリンス", fare: 1980, carClass: "普通車" },
  { id: "r-0619", date: "6/19 08:12", from: "自宅（広尾）", to: "羽田空港 第2", fare: 6240, carClass: "大型・ワゴン" },
]

// 会員ステータス
export const MEMBER = {
  name: "群青 太郎 様",
  number: "MIYAKO No. 0042-1188",
  tier: "ゴールド",
  points: 3480,
  pointsToNext: 1520,
  nextTier: "プラチナ",
  ytdRides: 38,
} as const

"use client"

import * as React from "react"
import {
  IconMapPin,
  IconFlag,
  IconCar,
  IconClock,
  IconPhone,
  IconMessage,
  IconReceipt,
  IconCircleFilled,
  IconChevronRight,
  IconShieldCheck,
} from "@tabler/icons-react"

import {
  PageHeader,
  Badge,
  Button,
  RadioCardGroup,
  RadioCard,
  AmountBreakdown,
  ListCard,
  LoyaltySummaryCard,
  PersonCell,
  Rating,
  RouteStops,
  Stepper,
  Separator,
  Banner,
  Tabs,
  TabsList,
  TabsTrigger,
  TabsContent,
  Spinner,
  formatCurrency,
  type StepperStep,
  type AmountLine,
} from "@gunjo/ui"

import {
  APP,
  CAR_CLASSES,
  PAYMENTS,
  TRIP,
  MATCH,
  FARE,
  HISTORY,
  MEMBER,
  type CarClassId,
  type PaymentId,
} from "./data"

/** ライドのライフサイクル。今回は「接近中（matched）」を主状態に、他はタブで到達可能に。 */
type Phase = "request" | "matched" | "enroute" | "payment"

const PHASE_STEPS: { key: Phase; label: string }[] = [
  { key: "request", label: "配車" },
  { key: "matched", label: "接近中" },
  { key: "enroute", label: "乗車中" },
  { key: "payment", label: "お支払い" },
]

function buildStepperSteps(active: Phase): StepperStep[] {
  const order = PHASE_STEPS.map((s) => s.key)
  const activeIdx = order.indexOf(active)
  return PHASE_STEPS.map((s, i): StepperStep => ({
    label: s.label,
    state: i < activeIdx ? "completed" : i === activeIdx ? "current" : "upcoming",
  }))
}

export function TaxiRideApp() {
  const [phase, setPhase] = React.useState<Phase>("matched")
  const [carClass, setCarClass] = React.useState<CarClassId>("standard")
  const [payment, setPayment] = React.useState<PaymentId>("credit")

  const selectedCar = CAR_CLASSES.find((c) => c.id === carClass)!
  const selectedPayment = PAYMENTS.find((p) => p.id === payment)!

  return (
    <div className="mx-auto flex min-h-dvh w-full max-w-md flex-col bg-background">
      <PageHeader
        title={APP.brand}
        subtitle={APP.app}
        onBack={() => {}}
        backLabel="メニューに戻る"
        actions={
          <Button variant="ghost" size="icon" aria-label="サポートに電話">
            <IconPhone className="size-5" aria-hidden="true" />
          </Button>
        }
      />

      {/* ── ライド進捗（リクエスト→接近→乗車中→完了） ───────────── */}
      <div className="border-b border-border">
        <Stepper steps={buildStepperSteps(phase)} aria-label="配車の進行状況" className="px-2 py-3" />
      </div>

      {/* スクロール領域。下部の固定アクションバーに隠れないよう pb を確保。 */}
      <main className="flex-1 overflow-y-auto px-4 pb-40 pt-4">
        <Tabs
          value={phase}
          onValueChange={(v) => setPhase(v as Phase)}
          className="w-full"
        >
          <TabsList className="mb-4 grid w-full grid-cols-4">
            <TabsTrigger value="request">配車</TabsTrigger>
            <TabsTrigger value="matched">接近中</TabsTrigger>
            <TabsTrigger value="enroute">乗車中</TabsTrigger>
            <TabsTrigger value="payment">支払い</TabsTrigger>
          </TabsList>

          {/* ── 配車リクエスト ──────────────────────────────── */}
          <TabsContent value="request" className="flex flex-col gap-5">
            <TripSummary />
            <section aria-labelledby="car-class-h" className="flex flex-col gap-2">
              <h2 id="car-class-h" className="text-sm font-semibold text-foreground">
                車種を選択
              </h2>
              <RadioCardGroup
                value={carClass}
                onValueChange={(v) => setCarClass(v as CarClassId)}
                aria-label="車種の選択"
              >
                {CAR_CLASSES.map((c) => (
                  <RadioCard
                    key={c.id}
                    value={c.id}
                    leading={<IconCar className="size-6 text-muted-foreground" aria-hidden="true" />}
                    title={c.name}
                    description={c.description}
                    tags={c.tag ? <Badge variant="secondary">{c.tag}</Badge> : undefined}
                    price={`${formatCurrency(c.estimateFrom)}〜`}
                    highlight={`到着まで約${c.etaMin}分`}
                  />
                ))}
              </RadioCardGroup>
            </section>

            <PaymentPicker payment={payment} onPayment={setPayment} />
          </TabsContent>

          {/* ── マッチング・接近（主状態） ───────────────────── */}
          <TabsContent value="matched" className="flex flex-col gap-5">
            <ApproachBanner etaMin={MATCH.etaMin} pct={MATCH.approachPct} />
            <DriverCard />
            <TripSummary />
            <FareEstimate selectedFrom={selectedCar.estimateFrom} selectedTo={selectedCar.estimateTo} />
            <PaymentInline payment={selectedPayment} onChange={() => setPhase("request")} />
          </TabsContent>

          {/* ── 乗車中 ──────────────────────────────────── */}
          <TabsContent value="enroute" className="flex flex-col gap-5">
            <Banner variant="default" icon={<IconCar className="size-5" aria-hidden="true" />}>
              <span className="font-semibold">乗車中</span> ・ 目的地まで約 {TRIP.estDurationMin - 6} 分
            </Banner>
            <RideProgress />
            <RunningFareNote />
          </TabsContent>

          {/* ── お支払い ─────────────────────────────────── */}
          <TabsContent value="payment" className="flex flex-col gap-5">
            <Banner variant="success" icon={<IconShieldCheck className="size-5" aria-hidden="true" />}>
              目的地に到着しました。ご乗車ありがとうございました。
            </Banner>
            <section aria-labelledby="fare-final-h" className="flex flex-col gap-2">
              <h2 id="fare-final-h" className="text-sm font-semibold text-foreground">
                確定運賃の内訳
              </h2>
              <div className="rounded-xl border border-border bg-card p-4">
                <AmountBreakdown lines={FINAL_FARE_LINES} total={FINAL_FARE_TOTAL} />
              </div>
            </section>
            <PaymentInline payment={selectedPayment} onChange={() => setPhase("request")} />
            <Button variant="outline" className="w-full gap-2">
              <IconReceipt className="size-4" aria-hidden="true" />
              領収書を表示
            </Button>

            <Separator className="my-1" />

            <AccountSection />
          </TabsContent>
        </Tabs>
      </main>

      {/* ── 永続ボトムアクションバー（sticky CTA + 走行料金/ETA + safe-area） ── */}
      <BottomActionBar
        phase={phase}
        car={selectedCar.name}
        fareFrom={selectedCar.estimateFrom}
        fareTo={selectedCar.estimateTo}
        finalTotal={FARE.total}
        etaMin={MATCH.etaMin}
        onPrimary={() => {
          setPhase((p) =>
            p === "request" ? "matched" : p === "matched" ? "enroute" : p === "enroute" ? "payment" : "payment"
          )
        }}
      />
    </div>
  )
}

/* ─────────────────────────────────────────────────────────────── */
/* 乗車地 / 行き先                                                   */
/* ─────────────────────────────────────────────────────────────── */
function TripSummary() {
  return (
    <section aria-label="乗車地と行き先" className="rounded-xl border border-border bg-card p-4">
      <ol className="flex flex-col">
        <li className="flex gap-3">
          <div className="flex flex-col items-center">
            <IconMapPin className="size-5 text-primary" aria-hidden="true" />
            <span className="my-1 h-6 w-px border-l border-dashed border-border" aria-hidden="true" />
          </div>
          <div className="min-w-0 flex-1 pb-2">
            <p className="text-xs text-muted-foreground">乗車地</p>
            <p className="truncate font-medium text-foreground">{TRIP.pickup.label}</p>
            <p className="truncate text-xs text-muted-foreground">{TRIP.pickup.address}</p>
          </div>
        </li>
        <li className="flex gap-3">
          <div className="flex flex-col items-center">
            <IconFlag className="size-5 text-foreground" aria-hidden="true" />
          </div>
          <div className="min-w-0 flex-1">
            <p className="text-xs text-muted-foreground">行き先</p>
            <p className="truncate font-medium text-foreground">{TRIP.dropoff.label}</p>
            <p className="truncate text-xs text-muted-foreground">{TRIP.dropoff.address}</p>
          </div>
        </li>
      </ol>
      <Separator className="my-3" />
      <div className="flex items-center justify-between text-xs text-muted-foreground">
        <span>走行距離 約 {TRIP.distanceKm} km</span>
        <span>所要 約 {TRIP.estDurationMin} 分</span>
      </div>
    </section>
  )
}

/* ─────────────────────────────────────────────────────────────── */
/* 接近バナー（到着まで○分 / 接近中）                               */
/* ─────────────────────────────────────────────────────────────── */
function ApproachBanner({ etaMin, pct }: { etaMin: number; pct: number }) {
  return (
    <section
      aria-label={`お迎えの車が接近中、到着まで約${etaMin}分`}
      className="rounded-xl border border-info-border bg-info-subtle p-4 text-info-subtle-foreground"
    >
      <div className="flex items-center gap-2">
        <Spinner size="sm" aria-hidden="true" />
        <span className="text-sm font-semibold">接近中 ・ まもなく到着</span>
      </div>
      <p className="mt-2 flex items-baseline gap-1">
        <span className="text-sm">到着まで</span>
        <span className="text-3xl font-bold tabular-nums">約 {etaMin}</span>
        <span className="text-sm">分</span>
      </p>
      <div
        className="mt-3 h-2 w-full overflow-hidden rounded-full bg-background/60"
        role="progressbar"
        aria-valuenow={pct}
        aria-valuemin={0}
        aria-valuemax={100}
        aria-label="車両の接近状況"
      >
        <div className="h-full rounded-full bg-info-border" style={{ width: `${pct}%` }} />
      </div>
    </section>
  )
}

/* ─────────────────────────────────────────────────────────────── */
/* マッチング済みドライバー / 車両カード                            */
/* ─────────────────────────────────────────────────────────────── */
function DriverCard() {
  return (
    <section aria-label="担当ドライバーと車両" className="flex flex-col gap-3 rounded-xl border border-border bg-card p-4">
      <PersonCell
        name={MATCH.driverName}
        secondary={
          <span className="flex items-center gap-1.5">
            <Rating value={MATCH.driverRating} size="sm" showValue reviewCount={MATCH.driverReviews} />
          </span>
        }
        tertiary={`乗務 ${MATCH.trips.toLocaleString("ja-JP")} 回`}
        avatar={{ fallback: "佐" }}
        presence="online"
        presenceLabel="運行中"
        trailing={
          <div className="flex gap-1">
            <Button variant="outline" size="icon" aria-label="ドライバーに電話">
              <IconPhone className="size-4" aria-hidden="true" />
            </Button>
            <Button variant="outline" size="icon" aria-label="ドライバーにメッセージ">
              <IconMessage className="size-4" aria-hidden="true" />
            </Button>
          </div>
        }
      />
      <Separator />
      <dl className="grid grid-cols-2 gap-x-3 gap-y-2 text-sm">
        <div>
          <dt className="text-xs text-muted-foreground">車種</dt>
          <dd className="font-medium text-foreground">{MATCH.carClassName}</dd>
        </div>
        <div>
          <dt className="text-xs text-muted-foreground">ナンバー</dt>
          <dd className="font-medium tabular-nums text-foreground">{MATCH.plate}</dd>
        </div>
        <div className="col-span-2">
          <dt className="text-xs text-muted-foreground">車体色</dt>
          <dd className="font-medium text-foreground">{MATCH.carColor}</dd>
        </div>
      </dl>
    </section>
  )
}

/* ─────────────────────────────────────────────────────────────── */
/* 料金の見積もり                                                   */
/* ─────────────────────────────────────────────────────────────── */
const ESTIMATE_LINES: AmountLine[] = [
  { label: "初乗り（1.096kmまで）", amount: FARE.base },
  { label: "距離・時間加算", amount: FARE.distance },
  { label: "迎車料金", amount: FARE.pickupFee },
  { label: "深夜割増（22時以降）", amount: FARE.lateNight, note: "22:00〜05:00 は2割増" },
]

function FareEstimate({ selectedFrom, selectedTo }: { selectedFrom: number; selectedTo: number }) {
  return (
    <section aria-labelledby="fare-est-h" className="flex flex-col gap-2">
      <div className="flex items-center justify-between">
        <h2 id="fare-est-h" className="text-sm font-semibold text-foreground">
          料金の見積もり
        </h2>
        <Badge variant="outline">見積もり</Badge>
      </div>
      <div className="rounded-xl border border-border bg-card p-4">
        <AmountBreakdown
          lines={ESTIMATE_LINES}
          total={{ label: "見積もり合計", amount: FARE.total }}
          formula="高速代・渋滞による加算は実費。到着時に確定します。"
        />
        <p className="mt-3 text-xs text-muted-foreground">
          目安レンジ {formatCurrency(selectedFrom)} 〜 {formatCurrency(selectedTo)}
        </p>
      </div>
    </section>
  )
}

const FINAL_FARE_LINES: AmountLine[] = [
  { label: "初乗り（1.096kmまで）", amount: FARE.base },
  { label: "距離・時間加算", amount: FARE.distance },
  { label: "迎車料金", amount: FARE.pickupFee },
  { label: "深夜割増（22時以降）", amount: FARE.lateNight },
  { label: "高速代", amount: FARE.highway },
]
const FINAL_FARE_TOTAL = { label: "お支払金額", amount: FARE.total, tone: "neutral" as const }

/* ─────────────────────────────────────────────────────────────── */
/* お支払い方法                                                     */
/* ─────────────────────────────────────────────────────────────── */
function PaymentPicker({
  payment,
  onPayment,
}: {
  payment: PaymentId
  onPayment: (p: PaymentId) => void
}) {
  return (
    <section aria-labelledby="pay-h" className="flex flex-col gap-2">
      <h2 id="pay-h" className="text-sm font-semibold text-foreground">
        お支払い方法
      </h2>
      <RadioCardGroup
        value={payment}
        onValueChange={(v) => onPayment(v as PaymentId)}
        aria-label="お支払い方法の選択"
      >
        {PAYMENTS.map((p) => (
          <RadioCard key={p.id} value={p.id} title={p.label} description={p.detail} />
        ))}
      </RadioCardGroup>
    </section>
  )
}

function PaymentInline({
  payment,
  onChange,
}: {
  payment: { label: string; detail: string }
  onChange: () => void
}) {
  return (
    <ListCard
      leading={<IconCircleFilled className="size-2.5 text-primary" aria-hidden="true" />}
      title={payment.label}
      description={payment.detail}
      meta="変更"
      onSelect={onChange}
      aria-label={`お支払い方法 ${payment.label}、変更`}
    />
  )
}

/* ─────────────────────────────────────────────────────────────── */
/* 乗車中：ルート進捗                                               */
/* ─────────────────────────────────────────────────────────────── */
function RideProgress() {
  return (
    <section aria-label="走行ルート" className="rounded-xl border border-border bg-card p-4">
      <RouteStops
        stops={[
          {
            id: "pickup",
            title: TRIP.pickup.label,
            description: TRIP.pickup.address,
            status: "completed",
            actualTime: "21:14",
          },
          {
            id: "via",
            title: "六本木通り 経由",
            description: "渋谷三丁目 → 西麻布",
            status: "current",
            plannedTime: "21:22",
          },
          {
            id: "dropoff",
            title: TRIP.dropoff.label,
            description: TRIP.dropoff.address,
            status: "pending",
            plannedTime: "21:30",
          },
        ]}
        statusLabels={{ completed: "通過", current: "走行中", pending: "到着予定" }}
      />
    </section>
  )
}

function RunningFareNote() {
  return (
    <div className="rounded-xl border border-border bg-card p-4">
      <p className="text-xs text-muted-foreground">走行中の料金（メーター）</p>
      <p className="mt-1 text-2xl font-bold tabular-nums text-foreground">{formatCurrency(1620)}</p>
      <p className="mt-1 text-xs text-muted-foreground">渋滞・経路により確定額は変動します</p>
    </div>
  )
}

/* ─────────────────────────────────────────────────────────────── */
/* 会員 / 配車履歴                                                  */
/* ─────────────────────────────────────────────────────────────── */
function AccountSection() {
  return (
    <section aria-labelledby="account-h" className="flex flex-col gap-4">
      <h2 id="account-h" className="text-sm font-semibold text-foreground">
        会員 ・ 配車履歴
      </h2>
      <LoyaltySummaryCard
        meta={`${MEMBER.name} ・ ${MEMBER.number}`}
        tier={<Badge variant="warning">{MEMBER.tier}会員</Badge>}
        balanceLabel="ポイント残高"
        balance={MEMBER.points.toLocaleString("ja-JP")}
        unit="P"
        secondary={[{ label: "本年の乗車", value: `${MEMBER.ytdRides} 回` }]}
        progress={{
          value: MEMBER.points,
          max: MEMBER.points + MEMBER.pointsToNext,
          label: `${MEMBER.nextTier}まであと ${MEMBER.pointsToNext.toLocaleString("ja-JP")}P`,
        }}
      />
      <div className="flex flex-col gap-2">
        {HISTORY.map((h) => (
          <ListCard
            key={h.id}
            leading={<IconClock className="size-5 text-muted-foreground" aria-hidden="true" />}
            title={`${h.from} → ${h.to}`}
            description={`${h.date} ・ ${h.carClass}`}
            meta={formatCurrency(h.fare)}
            status={<Badge variant="secondary">領収書</Badge>}
            trailing={<IconChevronRight className="size-5" aria-hidden="true" />}
            onSelect={() => {}}
            aria-label={`${h.date} の配車履歴 ${h.from}から${h.to}、${formatCurrency(h.fare)}`}
          />
        ))}
      </div>
    </section>
  )
}

