/* 永続ボトムアクションバー（hand-rolled — 該当コンポーネントなし） */
/* ─────────────────────────────────────────────────────────────── */
function BottomActionBar({
  phase,
  car,
  fareFrom,
  fareTo,
  finalTotal,
  etaMin,
  onPrimary,
}: {
  phase: Phase
  car: string
  fareFrom: number
  fareTo: number
  finalTotal: number
  etaMin: number
  onPrimary: () => void
}) {
  const config: Record<Phase, { left: React.ReactNode; sub: React.ReactNode; cta: string }> = {
    request: {
      left: `${formatCurrency(fareFrom)}〜`,
      sub: car,
      cta: "この内容で呼ぶ",
    },
    matched: {
      left: `${formatCurrency(fareFrom)}〜${formatCurrency(fareTo)}`,
      sub: `到着まで約 ${etaMin} 分`,
      cta: "配車をキャンセル",
    },
    enroute: {
      left: formatCurrency(1620),
      sub: "走行中（メーター）",
      cta: "ドライバーに連絡",
    },
    payment: {
      left: formatCurrency(finalTotal),
      sub: "確定運賃",
      cta: "支払う",
    },
  }
  const c = config[phase]
  const cancelTone = phase === "matched"

  return (
    <div
      className="sticky bottom-0 z-40 border-t border-border bg-background/95 backdrop-blur supports-[backdrop-filter]:bg-background/80"
      style={{ paddingBottom: "env(safe-area-inset-bottom)" }}
    >
      <div className="mx-auto flex w-full max-w-md items-center gap-3 px-4 py-3">
        <div className="min-w-0 flex-1">
          <p className="truncate text-lg font-bold tabular-nums text-foreground">{c.left}</p>
          <p className="truncate text-xs text-muted-foreground">{c.sub}</p>
        </div>
        <Button
          size="lg"
          variant={cancelTone ? "outline" : "default"}
          className="h-12 shrink-0 px-6 text-base"
          onClick={onPrimary}
        >
          {c.cta}
        </Button>
      </div>
    </div>
  )
}
